tool.command:
## ALNchain string matches the .1aln file extension
## symlink is used to bypass that restriction
ln -s '$input' 'input.1aln' &&

ALNchain
    -g${chain_params.max_gap}
    -l${chain_params.max_overlap}
    -p${chain_params.gap_penalty}
    -q${chain_params.overlap_penalty}
    -z${chain_params.score_drop}
    -s${filter_params.min_chain_score}
    -n${filter_params.min_chain_count}
    -c${filter_params.chain_coverage}
    -e${filter_params.seq_coverage}
    -f${filter_params.close_gap_limit}
    -o'output'
    'input.1aln' &&

cp 'output.1aln' '$output'
